mapper.select:
SELECT * FROM (


        SELECT id, 'device' AS source, device_id AS source_id, point_id,
        event_type_flag, confirm_flag, create_time,
        COALESCE(event_ext->>'content', '') AS message
        FROM dc3_device_event
        WHERE deleted = 0 AND tenant_id = #{tenantId}
        AND event_type_flag = #{eventTypeFlag}
        AND confirm_flag = #{confirmFlag}
        AND create_time >= #{from}


        SELECT id, 'driver' AS source, driver_id AS source_id, 0 AS point_id,
        event_type_flag, confirm_flag, create_time,
        COALESCE(event_ext->>'content', '') AS message
        FROM dc3_driver_event
        WHERE deleted = 0 AND tenant_id = #{tenantId}
        AND event_type_flag = #{eventTypeFlag}
        AND confirm_flag = #{confirmFlag}
        AND create_time >= #{from}


        (SELECT id, 'device' AS source, device_id AS source_id, point_id,
        event_type_flag, confirm_flag, create_time,
        COALESCE(event_ext->>'content', '') AS message
        FROM dc3_device_event
        WHERE deleted = 0 AND tenant_id = #{tenantId}
        AND event_type_flag = #{eventTypeFlag}
        AND confirm_flag = #{confirmFlag}
        AND create_time >= #{from})
        UNION ALL
        (SELECT id, 'driver' AS source, driver_id AS source_id, 0 AS point_id,
        event_type_flag, confirm_flag, create_time,
        COALESCE(event_ext->>'content', '') AS message
        FROM dc3_driver_event
        WHERE deleted = 0 AND tenant_id = #{tenantId}
        AND event_type_flag = #{eventTypeFlag}
        AND confirm_flag = #{confirmFlag}
        AND create_time >= #{from})


) rows
ORDER BY create_time DESC
LIMIT #{size} OFFSET #{offset}

choose.when:
SELECT COUNT(*) FROM dc3_device_event
WHERE deleted = 0 AND tenant_id = #{tenantId}
AND event_type_flag = #{eventTypeFlag}
AND confirm_flag = #{confirmFlag}
AND create_time >= #{from}

SELECT COUNT(*) FROM dc3_driver_event
WHERE deleted = 0 AND tenant_id = #{tenantId}
AND event_type_flag = #{eventTypeFlag}
AND confirm_flag = #{confirmFlag}
AND create_time >= #{from}

choose.otherwise:
SELECT
(SELECT COUNT(*) FROM dc3_device_event
WHERE deleted = 0 AND tenant_id = #{tenantId}
AND event_type_flag = #{eventTypeFlag}
AND confirm_flag = #{confirmFlag}
AND create_time >= #{from})
+ (SELECT COUNT(*) FROM dc3_driver_event
WHERE deleted = 0 AND tenant_id = #{tenantId}
AND event_type_flag = #{eventTypeFlag}
AND confirm_flag = #{confirmFlag}
AND create_time >= #{from})
